module top_module(
  input clk,
  input reset,
  input load_data,
  input [31:0] in_data,
  output reg [31:0] shift_out,
  output reg [31:0] parallel_out
);reg [31:0] unused_register;

  always @(posedge clk) begin
    if (reset) begin
      unused_register <= 32'b0;
    end else if (load_data) begin
      unused_register <= in_data;
    end else begin
      unused_register <= {unused_register[30:0], unused_register[31]};
    end
  end

  assign shift_out = unused_register;
  assign parallel_out = load_data ? in_data : unused_register;

endmodule
